const response = $input.first().json;
const content = response.content[0].text;
let analysis;
try {
  analysis = JSON.parse(content);
} catch(e) {
  const match = content.match(/\{[\s\S]*\}/);
  analysis = match ? JSON.parse(match[0]) : { score: 50, classificacao: 'WARM', justificativa: 'Análise indisponível', proximo_passo: 'Contato manual', melhor_produto: 'A definir' };
}
const lead = $('Formata Dados do Lead').first().json;
return [{ json: { ...lead, ...analysis, data_entrada: new Date().toISOString() } }];
